var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"호수의 파편이다! 우리는 호수의 품에 한 발짝 다가선 것이다!","JPN":"湖の破片だ！　私たちは湖に一歩近づいたのだ！","ENG":"It's a Fragment of the Lake! We are a step closer into the arms of the Lake!","TWN":"是湖水碎片！我們距離湖水的懷抱又近了一步！"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"마침내……! 마침내 우리의 오랜 숙원에 새로운 길이 열렸구나……!","JPN":"ついに……！　ついに私たちの長年の念願に新しい道が開かれた……！","ENG":"Alas...! A new path for our long-awaited wishes has finally opened...!","TWN":"終於……！終於我們的願望有了新的出路……！"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"학회원들이 동요하고 있군. 쉽게 가라앉지는 않겠어.","JPN":"学会員たちが動揺しているな。簡単には落ち着かないだろう。","ENG":"They are getting excited. This won't be easy to calm them down.","TWN":"學會成員都很激動。應該沒那麼容易平靜下來。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"저것이 오래 전 기관에게 빼앗긴 파편이오?","JPN":"あれが昔、機関に奪われた破片なのか？","ENG":"Is that the Fragment that the Institution stole from us so long ago?","TWN":"那個就是很久以前被機關搶走的碎片嗎？"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"네. 그렇답니다. 아직 이 세계에 남아 있는 저희 중에는 매우 거대한 축에 속하죠.","JPN":"はい。そうです。まだこの世界に残っている我々の中では巨大な部類に入ります。","ENG":"Yes, that is correct. It is one of the largest Fragments of us that remain in this world.","TWN":"嗯，是的。在還留在這個世界的我們當中，也屬於非常龐大的一類。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"그런가. 실로 감격스러운 순간이로군.","JPN":"そうか。実に感激的な瞬間であるな。","ENG":"Is that so? A truly thrilling moment, this is...","TWN":"是嗎，真是激動人心的時刻。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"저 파편으로 얼마나 많은 위업을 이룰 수 있을지…… 상상할 수 없을 지경이오.","JPN":"あの破片でどれほど多くの偉業が達成されていくのか……想像もできないくらいだ。","ENG":"I cannot imagine... what astonishing feats we can accomplish with it.","TWN":"用那個碎片可以成就多少豐功偉業……簡直無法想像。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"아. 의식을 치를 계획이에요.","JPN":"そうでした、儀式を行おうと思っていたんです。","ENG":"Oh. We are planning to perform a ritual.","TWN":"啊，我們打算舉行儀式。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"의식이라……. 어떤 의식이오?","JPN":"儀式……どのような儀式だ？","ENG":"A ritual...? Of what kind?","TWN":"儀式……什麼儀式？"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"이 세계의 법칙에 종속되지 않은, 다른 세계의 존재를 불러들이는 의식이랍니다.","JPN":"この世界の法則に属さない、違う世界の存在を呼び寄せる儀式です。","ENG":"A ritual that can summon beings from other realms who defies the laws of this world.","TWN":"召喚不附屬於這個世界法則的，其他世界存在的儀式。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"호오…… 그거 흥미롭구려. 고고학부장이 꽤나 아쉬워하겠소.","JPN":"ほう……それは興味深い。考古学部長が大いに残念がるだろうな。","ENG":"Ho-oh... Interesting. The Dean of Archeology must be very disappointed.","TWN":"噢噢……這個很有意思啊。考古學院院長看不到應該會很遺憾吧。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"괜찮아요. 교수님은 스스로 본인의 길을 개척할 역량이 있으시니까요.","JPN":"大丈夫です。教授はご自身で自らの道を開拓する力量をお持ちですから。","ENG":"It's okay. The Professor is fully capable of paving his own way.","TWN":"沒關係，因為教授有能力自行開闢自己的道路。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"그보다…… 준비는 어떻게 되어 가나요, 네퀴티아?","JPN":"それより……準備はどうですか？　ネキティア。","ENG":"Aside from that... Nequitia, how are things going with the preparations?","TWN":"話說回來……準備得怎麼樣了，莉奎蒂亞？"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"필요한 인원이 아직 도착하지 않았더군요, 왕이시여.","JPN":"必要な人員がまだ到着しておりません、王様。","ENG":"My lord, the required personnel has not arrived yet.","TWN":"需要的人員還沒有到齊，我的王。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"현재로서는 무대가 마련되어도 연주를 시작할 수 없습니다.","JPN":"現時点では舞台が用意されても演奏を始めることはできません。","ENG":"Even though the stage is set, we cannot begin the performance right now.","TWN":"即使現在舞台已經準備好了，暫時也不能開始演奏。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"필요한 인원이라고? 그걸 왜 이제 와서 말하는 것이오?","JPN":"必要な人員だと？　それをどうして今になって話すのだ？","ENG":"Required personnel? Why are you telling us that now?","TWN":"需要的人員？這種事你為什麼現在才說？"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"BASS_HARMONY_NULL_NULL","text":{"KOREA":"어머나, 인간 주제에 그렇게 사나운 말투를 쓰면 어떡해. 부드럽게 짖으렴.","JPN":"あら、人間の分際でその荒い言葉遣いは何なのかしら。優しく吠えなさい。","ENG":"Oh dear. Bark softly, human. Don't use that tone with me.","TWN":"哎呦，區區人類，說話口氣怎麼這麼凶，溫柔點。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L22_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"그 애가 부학회장님과 함께 실종되었다는 소식은 여기 도착한 다음에야 전해 들었거든요.","JPN":"あの子が副学会長様と一緒に失踪したということは、ここに着いてから聞きました。","ENG":"I learned about her disappearance with the Vice President only after I arrived.","TWN":"因為我們到這裡之後，才傳來那孩子和副學會長一起失蹤的消息。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L23_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"서신 같은 고리타분한 방식을 고집하는 건 시대착오적인 발상 아닐까요?","JPN":"手紙のような古くさい方法にこだわるのは、時代錯誤的な発想ではないでしょうか。","ENG":"Isn't it too anachronistic to insist on using letters for communication?","TWN":"執著於書信之類的陳舊方式，是落後於時代的想法吧？"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L25_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"아. 그 분이라면 곧 오실 거예요.","JPN":"あ。その方ならもうすぐ到着されるでしょう。","ENG":"Oh, she will arrive soon.","TWN":"啊，那位很快就會來的。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"우선은 음악 소리로 초대를 하기 전에, 길부터 닦아 두기로 할까요.","JPN":"まずは音楽で招待する前に、道から開けておきましょうか。","ENG":"Before making an invitation with music, shall we clear the pathway first?","TWN":"在邀請她過來之前，先用音樂聲清掃道路吧。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"협조 부탁드릴게요, 네퀴티아.","JPN":"ご協力をお願いします、ネキティア。","ENG":"Please do, Nequitia.","TWN":"麻煩你協助一下，莉奎蒂亞。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"음? 왜 연주를 시작 안 하시죠? 뭔가 더 필요하신가요?","JPN":"あら？　どうして演奏を始めないのですか？　ほかに何か必要なものでも？","ENG":"Hmm? Why aren't you playing? Is there something you need?","TWN":"嗯？為什麼不開始演奏呢？還需要別的什麼嗎？"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"왕이시여, 한 가지 여쭈어도 되겠습니까?","JPN":"王様、一つだけお尋ねしてもよろしいでしょうか。","ENG":"My lord, may I ask you a question?","TWN":"我的王，我能問你一個問題嗎？"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"물론이죠. 의문에 답을 드릴 수 있는 건 무척이나 기쁜 일이니까요.","JPN":"もちろんです。疑問にお答えできるのはとても嬉しいことですから。","ENG":"Of course. We'd be happy to answer your question.","TWN":"當然。解答別人的疑問是一件很開心的事。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"<color=#ffd34c>심연</color>에 닿는 차원의 균열을 일으키면, 왕께서도 상당한 부담을 짊어지십니다.","JPN":"<color=#ffd34c>深淵</color>に触れる次元の亀裂を発生させることは、王様にも相当な負担となるでしょう。","ENG":"Oh lord, you will bear a heavy burden when you create a dimensional rift that touches the <color=#ffd34c>abyss</color>.","TWN":"製造直達<color=#ffd34c>深淵</color>的次元裂縫，王也會承受相當大的負擔。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"상황에 따라서는……. 악의를 가진 이들에게 방해할 기회를 주는 것이기도 하죠.","JPN":"状況によっては……悪意を持った者たちに邪魔をする機会を与えることになります。","ENG":"Depending on the situation... You may be giving those with malicious intent a chance to sabotage.","TWN":"根據具體情況……也會給懷有惡意的人提供礙事的機會。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"어째서 그런 위험을 감수하시면서까지 의식을 강행하기로 하셨는지, 궁금해지는군요.","JPN":"どうしてそのような危険を冒してまで儀式を強行するとお決めになったのか、気になります。","ENG":"I am curious why you are willing to take that risk and proceed with the ritual.","TWN":"為什麼你甘願冒著這種風險，也要強行舉行儀式呢，我很好奇這件事。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"물론 어느 정도의 방해는 염두에 두고 있었답니다.","JPN":"もちろんある程度の邪魔は見越していましたよ。","ENG":"Or course, we are aware that there will be some hindrance.","TWN":"當然，我們考慮過會遇到某種程度的阻礙。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"하지만 강행하기로 한 까닭은…… 그렇네요. 당신은 의문을 가질 만도 하죠.","JPN":"でも強行すると決めた理由は……そうですね。あなたが疑問に思うのも当然です。","ENG":"But the reason why we are proceeding with it is... We see. You're right to have doubts about it.","TWN":"不過還要強行舉行儀式的原因……是啊，確實值得你懷疑。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"당신이 멘탈 프린팅에 느끼는 미련을, 저는 짊어지고 싶지 않아요. 그뿐이랍니다.","JPN":"あなたがメンタル・プリンティングに抱いている未練を、我々は背負いたくありません。それだけです。","ENG":"However, we do not want to have that lingering feeling that you feel about Mental Printing. That is all.","TWN":"是因為我們不想背負你對智力複印的迷戀，僅此而已。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"……미련을 짊어지고 싶지 않다. 그렇군요.","JPN":"……未練を背負いたくない。そうですか。","ENG":"...Not wanting any lingering feelings. I see.","TWN":"……不想背負迷戀，原來如此。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_LAUGH"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"알겠습니다. 뜻에 따르기로 하죠.","JPN":"承知しました。その意志に従いましょう。","ENG":"I understand. I will start playing.","TWN":"知道了，我會按照你的意思去做。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"이렇게 쉽게 차원에 균열을 만들다니…….","JPN":"これほど簡単に次元に亀裂を発生させるとは……","ENG":"How could a dimensional rift open so easily...?","TWN":"居然這麼輕易就製造了次元裂縫……"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_WIND"},{"id":"L42_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"학회장, 당신에게 학회란 무엇인지 궁금해지는구려.","JPN":"学会長、あなたにとって学会とは何なのかが気になるな。","ENG":"President, I'm interested to hear what the Society means to you.","TWN":"學會長，我很好奇對於你來說，學會是什麼。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"물론 저희의 보금자리랍니다, 소장님.","JPN":"もちろん我々の居場所ですよ、所長。","ENG":"Well, Chief. It is our home.","TWN":"當然是我們的家了，所長。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"의식을 진행하는 동안, 주위에 잡음이 없게 정리를 부탁드릴게요.","JPN":"儀式を行っている間、周りに雑音のないように片づけをお願いします。","ENG":"Please keep the surroundings quiet while the ritual is being performed.","TWN":"儀式進行期間，請把附近清理乾淨，保證沒有雜訊。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"작은 불순물도 문제를 일으킬 수 있으니까요.","JPN":"小さな不純物でも問題になりかねませんから。","ENG":"Even the slightest impurity can cause trouble.","TWN":"因為哪怕只是一個小小的雜質，也有可能會引發問題。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};